#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1 || n > 1000) return 0;

    int *arr = (int *)malloc((size_t)n * sizeof(int));
    if (!arr) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            free(arr);
            return 0;
        }
    }

    int distinct = 0;
    for (int i = 0; i < n; i++) {
        int seen = 0;
        for (int j = 0; j < i; j++) {
            if (arr[j] == arr[i]) {
                seen = 1;
                break;
            }
        }
        if (!seen) distinct++;
    }

    printf("%d\n", distinct);
    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char buffer[201];
    if (!fgets(buffer, sizeof(buffer), stdin)) return 0;

    size_t len = strlen(buffer);
    if (len > 0 && buffer[len - 1] == '\n') {
        buffer[len - 1] = '\0';
        len--;
    }

    char *text = (char *)malloc(len + 1);
    if (!text) return 0;

    for (size_t i = 0; i <= len; i++) {
        text[i] = buffer[i];
    }

    for (size_t i = 0; i < len / 2; i++) {
        char tmp = text[i];
        text[i] = text[len - 1 - i];
        text[len - 1 - i] = tmp;
    }

    printf("%s\n", text);
    free(text);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int capacity = 8;
    int count = 0;
    int *arr = (int *)malloc((size_t)capacity * sizeof(int));
    if (!arr) return 0;

    while (1) {
        int x;
        if (scanf("%d", &x) != 1) {
            free(arr);
            return 0;
        }
        if (x == -1) break;

        if (count == capacity) {
            capacity *= 2;
            int *tmp = (int *)realloc(arr, (size_t)capacity * sizeof(int));
            if (!tmp) {
                free(arr);
                return 0;
            }
            arr = tmp;
        }
        arr[count++] = x;
    }

    long long sum = 0;
    for (int i = 0; i < count; i++) {
        sum += arr[i];
    }

    printf("%lld\n", sum);
    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char temp[301];
    if (!fgets(temp, sizeof(temp), stdin)) return 0;

    size_t len = strlen(temp);
    if (len > 0 && temp[len - 1] == '\n') {
        temp[len - 1] = '\0';
        len--;
    }

    char *s = (char *)malloc(len + 1);
    if (!s) return 0;

    for (size_t i = 0; i <= len; i++) s[i] = temp[i];

    int letters = 0, digits = 0, spaces = 0, others = 0;
    for (size_t i = 0; i < len; i++) {
        unsigned char c = (unsigned char)s[i];
        if (isalpha(c)) letters++;
        else if (isdigit(c)) digits++;
        else if (isspace(c)) spaces++;
        else others++;
    }

    printf("%d %d %d %d\n", letters, digits, spaces, others);
    free(s);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int capacity = 4;
    int count = 0;
    int *arr = (int *)malloc((size_t)capacity * sizeof(int));
    if (!arr) return 0;

    while (1) {
        int x;
        if (scanf("%d", &x) != 1) {
            free(arr);
            return 0;
        }
        if (x == 0) break;

        if (count == capacity) {
            capacity *= 2;
            int *tmp = (int *)realloc(arr, (size_t)capacity * sizeof(int));
            if (!tmp) {
                free(arr);
                return 0;
            }
            arr = tmp;
        }
        arr[count++] = x;
    }

    for (int i = count - 1; i >= 0; i--) {
        printf("%d", arr[i]);
        if (i > 0) printf(" ");
    }
    printf("\n");

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1 || n > 1000) return 0;

    int *arr = (int *)malloc((size_t)n * sizeof(int));
    if (!arr) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            free(arr);
            return 0;
        }
    }

    long long sum = 0;
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] > 0) {
            sum += arr[i];
            count++;
        }
    }

    if (count == 0) {
        printf("0.00\n");
    } else {
        printf("%.2f\n", (double)sum / count);
    }

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char temp[201];
    if (!fgets(temp, sizeof(temp), stdin)) return 0;

    size_t len = strlen(temp);
    if (len > 0 && temp[len - 1] == '\n') {
        temp[len - 1] = '\0';
        len--;
    }

    size_t start = 0;
    while (start < len && isspace((unsigned char)temp[start])) start++;

    size_t end = start;
    while (end < len && !isspace((unsigned char)temp[end])) end++;

    size_t word_len = end - start;
    char *word = (char *)malloc(word_len + 1);
    if (!word) return 0;

    for (size_t i = 0; i < word_len; i++) {
        word[i] = temp[start + i];
    }
    word[word_len] = '\0';

    printf("%s\n", word);
    free(word);
    return 0;
}

#include <stdio.h>
